div.script:
                                    function myFunction(event) {
  console.log("---------------------------",event)
  input_link = event.getElementsByTagName("input")

  web_page_tag= document.getElementsByClassName('o_wslides_fs_content')
  var ifrm = document.createElement('iframe');
ifrm.setAttribute('title', input_link[0].value);
ifrm.setAttribute('src', '/slides_survey/slide/get_certification_url?slide_id='+input_link[0].value); // assign an id
ifrm.setAttribute('width', '100%'); // assign an id



  console.log("gggggggggggggggggggggggggggggggggg",input_link[0].value,web_page_tag,ifrm)
  web_page_tag[0].innerHTML=''
  web_page_tag[0].appendChild(ifrm)
}
